ntDescription = null,                        modifier = Modifier                            .size(31.dp)                            .align(Alignment.BottomStart),                        contentScale = ContentScale.Crop                    )                }                Text(                    text = "DON'T MISS IT",                    style = MaterialTheme.typography.titleLarge,                    fontWeight = FontWeight.W900,                    fontSize = 34.sp,                    color = Primary,                    textAlign = TextAlign.Center                )                Box(                    modifier = Modifier                        .width(246.dp)                        .height(260.dp)                ){                    Box(                        modifier = Modifier                            .padding(top = 18.dp, end = 26.dp)                            .rotate(-10.8f)                            .clip(RoundedCornerShape(18.35.dp))                            .width(159.64.dp)                            .height(220.19.dp)                            .border(1.dp, Color.White,RoundedCornerShape(18.35.dp))                            .align(Alignment.TopEnd),                    ){                        TemplateCard(                            name = "",                            thumbnailPath = item.thumbnailPath,                            aspectRatio = (159.64f/220.19f),                            isPremium = false,                            showHotTag = true,  // Show HOT tag for top 10 templates                            useCount = 0,  // For backward compatibility                            viewCount =0,  // Display count shown to users                            modifier = Modifier,                            onClick = {//                                Analytics.trackTemplateClick(//                                    templateId = template.id,//                                    templateName = template.name,//                                    location = AnalyticsEvent.Value.Location.GALLERY_TEMPLATE//                                )//                                onTemplateClick(template, AnalyticsEvent.Value.Location.GALLERY_TEMPLATE)                            }                        )                    }                    Image(                        painter = painterResource(R.drawable.img_bg_template_trend),                        contentDescription = null,                        contentScale = ContentScale.Crop,                        modifier = Modifier.matchParentSize()                    )                }                Text(                    text = item.name,                    style = MaterialTheme.typography.titleLarge,                    fontWeight = FontWeight.W700,                    fontSize = 28.sp,                    color = Neutral_N200,                    textAlign = TextAlign.Center                )                Spacer(Modifier.height(32.dp))                CTAPrimaryButton(                    text = "Try it now"                ){                    onCTA.invoke()                }            }        }    }}@Preview(showBackground = true)@Composableprivate fun PopupTrendingTemplatePreview() {    VideoMakerTheme {        Box(            modifier = Modifier                .fillMaxSize()                .background(SplashBackground)        ) {            PopupTrendingTemplate(                VideoTemplate(id = "10", name = "Vintage Love", songId = 10, effectSetId = "e10", aspectRatio = "1:1"),                onCTA = {},                onDismiss = {}            )        }    }}